// Package matchlen finds the length of the common prefix of two byte slices —
// the core primitive of every LZ-family compressor's match-finder (LZ4, zstd,
// LZFSE/LZVN, brotli, …). The hot comparison loop is SIMD on amd64, arm64,
// loong64 and riscv64 (assembly generated by go-asmgen) and a portable 8-byte
// scalar elsewhere — all on plain `go build`, no cgo, no GOEXPERIMENT.
package matchlen

// MatchLen returns the number of leading bytes that a and b share: the largest
// n <= min(len(a), len(b)) with a[:n] == b[:n].
func MatchLen(a, b []byte) int {
	limit := len(a)
	if len(b) < limit {
		limit = len(b)
	}
	// bulkMatch runs the wide SIMD/word loop; the byte tail finishes the < stride
	// remainder. If bulkMatch stopped on a mismatch, the tail's a[n]==b[n] test
	// fails immediately, so this stays correct either way.
	n := bulkMatch(a, b, limit)
	for n < limit && a[n] == b[n] {
		n++
	}
	return n
}
